import { Kline } from '../types';

export const calculateEMA = (data: number[], period: number) => {
  if (data.length < period) return [];
  const k = 2 / (period + 1);
  const ema = [data[0]];
  for (let i = 1; i < data.length; i++) {
    ema.push(data[i] * k + ema[i - 1] * (1 - k));
  }
  return ema;
};

export const calculateRSI = (data: number[], period: number = 14) => {
  if (data.length <= period) return [];
  const rsi = [];
  let gains = 0;
  let losses = 0;

  for (let i = 1; i <= period; i++) {
    const diff = data[i] - data[i - 1];
    if (diff >= 0) gains += diff;
    else losses -= diff;
  }

  let avgGain = gains / period;
  let avgLoss = losses / period;
  rsi.push(100 - 100 / (1 + avgGain / avgLoss));

  for (let i = period + 1; i < data.length; i++) {
    const diff = data[i] - data[i - 1];
    let gain = diff >= 0 ? diff : 0;
    let loss = diff < 0 ? -diff : 0;
    avgGain = (avgGain * (period - 1) + gain) / period;
    avgLoss = (avgLoss * (period - 1) + loss) / period;
    rsi.push(100 - 100 / (1 + avgGain / avgLoss));
  }
  return Array(period).fill(null).concat(rsi);
};

export const calculateMACD = (data: number[]) => {
  const ema12 = calculateEMA(data, 12);
  const ema26 = calculateEMA(data, 26);
  if (ema26.length < data.length) return { macd: [], signal: [], hist: [] };

  const macd = ema12.map((v, i) => v - ema26[i]);
  const signal = calculateEMA(macd.slice(25), 9);
  const fullSignal = Array(25 + 8).fill(null).concat(signal);
  const hist = macd.map((v, i) => (fullSignal[i] !== null ? v - fullSignal[i] : null));

  return { macd, signal: fullSignal, hist };
};

export const calculateATR = (klines: Kline[], period: number = 14) => {
  if (klines.length <= period) return [];
  const trs = klines.map((k, i) => {
    if (i === 0) return k.h - k.l;
    return Math.max(k.h - k.l, Math.abs(k.h - klines[i - 1].c), Math.abs(k.l - klines[i - 1].c));
  });

  const atr = [trs.slice(0, period).reduce((a, b) => a + b, 0) / period];
  for (let i = period; i < trs.length - 1; i++) {
    atr.push((atr[atr.length - 1] * (period - 1) + trs[i]) / period);
  }
  return Array(period).fill(null).concat(atr);
};

export const calculateADX = (klines: Kline[], period: number = 14) => {
  if (klines.length <= period * 2) return { adx: [], plusDI: [], minusDI: [] };

  const plusDM = klines.map((k, i) => {
    if (i === 0) return 0;
    const upMove = k.h - klines[i-1].h;
    const downMove = klines[i-1].l - k.l;
    return (upMove > downMove && upMove > 0) ? upMove : 0;
  });

  const minusDM = klines.map((k, i) => {
    if (i === 0) return 0;
    const upMove = k.h - klines[i-1].h;
    const downMove = klines[i-1].l - k.l;
    return (downMove > upMove && downMove > 0) ? downMove : 0;
  });

  const trs = klines.map((k, i) => {
    if (i === 0) return k.h - k.l;
    return Math.max(k.h - k.l, Math.abs(k.h - klines[i - 1].c), Math.abs(k.l - klines[i - 1].c));
  });

  const smooth = (data: number[]) => {
    const res = [data.slice(0, period).reduce((a, b) => a + b, 0)];
    for (let i = period; i < data.length; i++) {
      res.push(res[res.length - 1] - (res[res.length - 1] / period) + data[i]);
    }
    return res;
  };

  const str = smooth(trs);
  const spdm = smooth(plusDM);
  const smdm = smooth(minusDM);

  const plusDI = spdm.map((v, i) => 100 * v / str[i]);
  const minusDI = smdm.map((v, i) => 100 * v / str[i]);

  const dx = plusDI.map((v, i) => 100 * Math.abs(v - minusDI[i]) / (v + minusDI[i]));
  const adx = [dx.slice(0, period).reduce((a, b) => a + b, 0) / period];
  for (let i = period; i < dx.length; i++) {
    adx.push((adx[adx.length - 1] * (period - 1) + dx[i]) / period);
  }

  const offset = period * 2 - 1;
  return { 
    adx: Array(offset).fill(null).concat(adx), 
    plusDI: Array(period - 1).fill(null).concat(plusDI), 
    minusDI: Array(period - 1).fill(null).concat(minusDI) 
  };
};

import { BINANCE_FUTURES_REST, BINANCE_FUTURES_WS } from '../constants';
import { Timeframe, Kline } from '../types';

export const fetchTopCoins = async (limit: number = 100) => {
  try {
    const response = await fetch(`${BINANCE_FUTURES_REST}/fapi/v1/ticker/24hr`);
    const data = await response.json();
    return data
      .filter((item: any) => item.symbol.endsWith('USDT'))
      .sort((a: any, b: any) => parseFloat(b.quoteVolume) - parseFloat(a.quoteVolume))
      .slice(0, limit)
      .map((item: any) => item.symbol);
  } catch (error) {
    console.error('Error fetching top coins:', error);
    return [];
  }
};

export const fetchKlines = async (symbol: string, interval: Timeframe, limit: number = 500): Promise<Kline[]> => {
  try {
    const response = await fetch(`${BINANCE_FUTURES_REST}/fapi/v1/klines?symbol=${symbol}&interval=${interval}&limit=${limit}`);
    const data = await response.json();
    return data.map((d: any) => ({
      t: d[0],
      o: parseFloat(d[1]),
      h: parseFloat(d[2]),
      l: parseFloat(d[3]),
      c: parseFloat(d[4]),
      v: parseFloat(d[5]),
      x: true
    }));
  } catch (error) {
    console.error(`Error fetching klines for ${symbol}:`, error);
    return [];
  }
};

export const connectScannerWS = (symbols: string[], interval: Timeframe, onMessage: (msg: any) => void) => {
  const streams = symbols.map(s => `${s.toLowerCase()}@kline_${interval}`).join('/');
  const ws = new WebSocket(`${BINANCE_FUTURES_WS}${streams}`);

  ws.onmessage = (event) => {
    const data = JSON.parse(event.data);
    onMessage(data);
  };

  return ws;
};

export const connectMarkPriceWS = (symbols: string[], onMessage: (msg: any) => void) => {
  const streams = symbols.map(s => `${s.toLowerCase()}@markPrice@1s`).join('/');
  const ws = new WebSocket(`${BINANCE_FUTURES_WS}${streams}`);

  ws.onmessage = (event) => {
    const data = JSON.parse(event.data);
    onMessage(data);
  };

  return ws;
};

import { Kline, PositionSide, Signal, IndicatorConfig, AdvancedSettings, Timeframe } from '../types';
import { calculateEMA, calculateRSI, calculateMACD, calculateATR, calculateADX } from './indicators';

export const evaluateSignal = (
  symbol: string,
  klines: Kline[],
  timeframe: Timeframe,
  indicators: IndicatorConfig,
  advanced: AdvancedSettings
): Signal | null => {
  if (klines.length < 200) return null;

  const closes = klines.map(k => k.c);
  const ema20 = calculateEMA(closes, 20);
  const ema50 = calculateEMA(closes, 50);
  const ema200 = calculateEMA(closes, 200);
  const rsi = calculateRSI(closes, 14);
  const { macd, signal: macdSignal, hist: macdHist } = calculateMACD(closes);
  const atr = calculateATR(klines, 14);
  const { adx, plusDI, minusDI } = calculateADX(klines, 14);

  const lastIdx = klines.length - 1;
  const currentPrice = closes[lastIdx];
  const lastKline = klines[lastIdx];
  const prevKline = klines[lastIdx - 1];

  let score = 40;
  const reasons: string[] = [];
  let isLong = true;
  let isShort = true;

  // EMA 20/50
  if (indicators.ema20_50) {
    const lEma20 = ema20[ema20.length - 1];
    const lEma50 = ema50[ema50.length - 1];
    if (lEma20 > lEma50) {
      score += 10;
      isShort = false;
      reasons.push('EMA20 > EMA50');
    } else {
      score += 10;
      isLong = false;
      reasons.push('EMA20 < EMA50');
    }
  }

  // EMA 200
  if (indicators.ema200) {
    const lEma200 = ema200[ema200.length - 1];
    if (currentPrice > lEma200) {
      score += 10;
      isShort = false;
      reasons.push('Giá > EMA200');
    } else {
      score += 10;
      isLong = false;
      reasons.push('Giá < EMA200');
    }
  }

  // RSI
  if (indicators.rsi14) {
    const lRsi = rsi[rsi.length - 1];
    const pRsi = rsi[rsi.length - 2];
    if (lRsi > 50 && lRsi > pRsi) {
      score += 10;
      isShort = false;
      reasons.push('RSI > 50 & Đang tăng');
    } else if (lRsi < 50 && lRsi < pRsi) {
      score += 10;
      isLong = false;
      reasons.push('RSI < 50 & Đang giảm');
    } else {
      isLong = false;
      isShort = false;
    }
  }

  // MACD
  if (indicators.macd) {
    const lHist = macdHist[macdHist.length - 1] || 0;
    const pHist = macdHist[macdHist.length - 2] || 0;
    if (lHist > 0) {
      score += (lHist > pHist) ? 15 : 5;
      isShort = false;
      reasons.push('MACD Histogram Dương');
    } else if (lHist < 0) {
      score += (lHist < pHist) ? 15 : 5;
      isLong = false;
      reasons.push('MACD Histogram Âm');
    }
  }

  // ADX
  if (indicators.adx14) {
    const lAdx = adx[adx.length - 1] || 0;
    const lPdi = plusDI[plusDI.length - 1] || 0;
    const lMdi = minusDI[minusDI.length - 1] || 0;
    if (lAdx < advanced.adxMin) {
      return null; // Side-way filter
    }
    if (lPdi > lMdi) {
      score += 10;
      isShort = false;
      reasons.push('ADX Trend Tăng (+DI > -DI)');
    } else {
      score += 10;
      isLong = false;
      reasons.push('ADX Trend Giảm (-DI > +DI)');
    }
  }

  // ATR Volatility
  const lastAtr = atr[atr.length - 1] || 0;
  const atrPct = (lastAtr / currentPrice) * 100;
  if (indicators.atr14) {
    if (atrPct < advanced.minVolPct) return null; // Low volatility filter
    score += (atrPct > advanced.minVolPct * 1.5) ? 10 : 0;
  }

  // Final Scoring
  if (score < advanced.thresholdScore) return null;

  const side = isLong ? PositionSide.LONG : (isShort ? PositionSide.SHORT : null);
  if (!side) return null;

  // Calculate Entry, TP, SL (Simple ATR Based)
  const entry = currentPrice;
  const slMult = 1.6;
  const tp1Mult = 1.5;
  const tp2Mult = 2.6;

  const sl = side === PositionSide.LONG ? entry - lastAtr * slMult : entry + lastAtr * slMult;
  const tp1 = side === PositionSide.LONG ? entry + lastAtr * tp1Mult : entry - lastAtr * tp1Mult;
  const tp2 = side === PositionSide.LONG ? entry + lastAtr * tp2Mult : entry - lastAtr * tp2Mult;

  return {
    id: `${symbol}-${timeframe}-${Date.now()}`,
    symbol,
    side,
    entry,
    tp1,
    tp2,
    sl,
    score,
    timeframe,
    timestamp: Date.now(),
    reasons
  };
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Timeframe, FilterMode, MarginMode, PositionSide, IndicatorConfig, 
  AdvancedSettings, TradeSettings, Order, Signal, ConnectionStatus, CoinData 
} from './types';
import { 
  DEFAULT_INDICATORS, DEFAULT_ADVANCED, DEFAULT_TRADE_SETTINGS, 
  TIMEFRAMES, PRESETS 
} from './constants';
import { fetchTopCoins, fetchKlines, connectScannerWS, connectMarkPriceWS } from './services/binance';
import { evaluateSignal } from './services/signalEngine';

// Components
import ScannerTab from './components/ScannerTab';
import OrdersTab from './components/OrdersTab';
import HistoryTab from './components/HistoryTab';
import SettingsTab from './components/SettingsTab';
import Header from './components/Header';
import Notification from './components/Notification';
import ChartModal from './components/ChartModal';

const App: React.FC = () => {
  // Navigation
  const [activeTab, setActiveTab] = useState<'scanner' | 'orders' | 'history' | 'settings'>('scanner');

  // Configuration
  const [timeframe, setTimeframe] = useState<Timeframe>('15m');
  const [coinCount, setCoinCount] = useState<number>(50);
  const [filterMode, setFilterMode] = useState<FilterMode>(FilterMode.NORMAL);
  const [indicators, setIndicators] = useState<IndicatorConfig>(DEFAULT_INDICATORS);
  const [advanced, setAdvanced] = useState<AdvancedSettings>(DEFAULT_ADVANCED);
  const [tradeSettings, setTradeSettings] = useState<TradeSettings>(DEFAULT_TRADE_SETTINGS);

  // App State
  const [isScanning, setIsScanning] = useState(false);
  const [status, setStatus] = useState<ConnectionStatus>({
    connected: false,
    reconnecting: false,
    lastUpdate: Date.now(),
    scanningCount: 0
  });
  const [openOrders, setOpenOrders] = useState<Order[]>([]);
  const [history, setHistory] = useState<Order[]>([]);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [selectedCoinForChart, setSelectedCoinForChart] = useState<string | null>(null);

  // Data refs for engine
  const coinDataMap = useRef<Map<string, CoinData>>(new Map());
  const wsRef = useRef<WebSocket | null>(null);
  const priceWsRef = useRef<WebSocket | null>(null);
  const lastSignalTime = useRef<Map<string, number>>(new Map());

  // Initialization
  useEffect(() => {
    // Sync presets when filterMode changes
    if (filterMode !== FilterMode.CUSTOM) {
      const preset = (PRESETS as any)[filterMode];
      if (preset) {
        setIndicators(preset.indicators);
        setAdvanced(preset.advanced);
        setTradeSettings(prev => ({ ...prev, leverage: preset.leverage }));
      }
    }
  }, [filterMode]);

  const addNotification = (title: string, message: string, type: 'info' | 'success' | 'error' = 'info') => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, title, message, type }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 5000);
  };

  const handleOpenOrder = useCallback((signal: Signal) => {
    // Spam check
    const lastTime = lastSignalTime.current.get(signal.symbol) || 0;
    if (Date.now() - lastTime < tradeSettings.cooldownMin * 60000) return;
    if (openOrders.length >= tradeSettings.maxOpenTrades) return;
    if (openOrders.some(o => o.symbol === signal.symbol && o.timeframe === signal.timeframe)) return;

    const newOrder: Order = {
      id: signal.id,
      symbol: signal.symbol,
      side: signal.side,
      entryPrice: signal.entry,
      currentPrice: signal.entry,
      tp1: signal.tp1,
      tp2: signal.tp2,
      sl: signal.sl,
      leverage: tradeSettings.leverage,
      notional: tradeSettings.marginPerTrade * tradeSettings.leverage,
      pnlUsdt: 0,
      pnlPct: 0,
      status: 'OPEN',
      openTime: Date.now(),
      timeframe: signal.timeframe,
      hitTP1: false
    };

    setOpenOrders(prev => [...prev, newOrder]);
    lastSignalTime.current.set(signal.symbol, Date.now());
    addNotification(`Lệnh mới: ${signal.symbol}`, `${signal.side} @ ${signal.entry}`, 'success');
  }, [tradeSettings, openOrders.length]);

  const handleCloseOrder = useCallback((id: string, reason: 'TP1' | 'TP2' | 'SL' | 'MANUAL', closePrice: number) => {
    setOpenOrders(prev => {
      const order = prev.find(o => o.id === id);
      if (!order) return prev;

      const closedOrder: Order = {
        ...order,
        status: 'CLOSED',
        closePrice,
        closeReason: reason,
        closeTime: Date.now()
      };

      setHistory(h => [closedOrder, ...h]);
      addNotification(`Đã đóng lệnh ${order.symbol}`, `${reason} @ ${closePrice}`, reason === 'SL' ? 'error' : 'success');
      return prev.filter(o => o.id !== id);
    });
  }, []);

  const updateOrderPrices = useCallback((symbol: string, price: number) => {
    setOpenOrders(prev => prev.map(order => {
      if (order.symbol !== symbol) return order;

      const isLong = order.side === PositionSide.LONG;
      const pnlPct = isLong ? (price - order.entryPrice) / order.entryPrice : (order.entryPrice - price) / order.entryPrice;
      const pnlUsdt = order.notional * pnlPct;

      // Trigger logic
      if (isLong) {
        if (price <= order.sl) {
          setTimeout(() => handleCloseOrder(order.id, 'SL', price), 0);
        } else if (price >= order.tp1 && !order.hitTP1) {
          if (tradeSettings.takeProfit50AtTP1) {
            // Semi-close logic could go here, for simplicity we just track hitTP1
          }
          if (tradeSettings.moveSLToEntryAtTP1) {
            order.sl = order.entryPrice;
          }
          order.hitTP1 = true;
          if (!tradeSettings.useTP2) setTimeout(() => handleCloseOrder(order.id, 'TP1', price), 0);
        } else if (tradeSettings.useTP2 && price >= order.tp2) {
          setTimeout(() => handleCloseOrder(order.id, 'TP2', price), 0);
        }
      } else {
        if (price >= order.sl) {
          setTimeout(() => handleCloseOrder(order.id, 'SL', price), 0);
        } else if (price <= order.tp1 && !order.hitTP1) {
          if (tradeSettings.moveSLToEntryAtTP1) {
            order.sl = order.entryPrice;
          }
          order.hitTP1 = true;
          if (!tradeSettings.useTP2) setTimeout(() => handleCloseOrder(order.id, 'TP1', price), 0);
        } else if (tradeSettings.useTP2 && price <= order.tp2) {
          setTimeout(() => handleCloseOrder(order.id, 'TP2', price), 0);
        }
      }

      return { ...order, currentPrice: price, pnlUsdt, pnlPct: pnlPct * 100 * order.leverage };
    }));
  }, [handleCloseOrder, tradeSettings]);

  const startScanner = async () => {
    setIsScanning(true);
    setStatus(prev => ({ ...prev, reconnecting: true }));

    const symbols = await fetchTopCoins(coinCount);
    setStatus(prev => ({ ...prev, scanningCount: symbols.length, connected: true, reconnecting: false }));

    // Fetch initial klines
    for (const symbol of symbols) {
      const klines = await fetchKlines(symbol, timeframe);
      coinDataMap.current.set(symbol, { symbol, price: 0, markPrice: 0, volume24h: 0, klines });
    }

    // Connect WebSocket
    wsRef.current = connectScannerWS(symbols, timeframe, (msg) => {
      const { s: symbol, k } = msg.data || msg;
      if (!k) return;

      const data = coinDataMap.current.get(symbol);
      if (!data) return;

      const newKline: Kline = {
        t: k.t, o: parseFloat(k.o), h: parseFloat(k.h), l: parseFloat(k.l), c: parseFloat(k.c), v: parseFloat(k.v), x: k.x
      };

      // Update klines cache
      const updatedKlines = [...data.klines];
      if (updatedKlines[updatedKlines.length - 1].t === newKline.t) {
        updatedKlines[updatedKlines.length - 1] = newKline;
      } else {
        updatedKlines.push(newKline);
        if (updatedKlines.length > 500) updatedKlines.shift();
      }
      data.klines = updatedKlines;
      data.price = newKline.c;

      // Update scanner UI status
      setStatus(prev => ({ ...prev, lastUpdate: Date.now() }));

      // Evaluate on candle close
      if (newKline.x) {
        const signal = evaluateSignal(symbol, updatedKlines, timeframe, indicators, advanced);
        if (signal) {
          handleOpenOrder(signal);
        }
      }
    });

    // Connect Price WebSocket for open orders tracking
    priceWsRef.current = connectMarkPriceWS(symbols, (msg) => {
      const { s: symbol, p: price } = msg.data || msg;
      if (symbol && price) {
        updateOrderPrices(symbol, parseFloat(price));
      }
    });
  };

  const stopScanner = () => {
    setIsScanning(false);
    wsRef.current?.close();
    priceWsRef.current?.close();
    setStatus(prev => ({ ...prev, connected: false, scanningCount: 0 }));
  };

  return (
    <div className="min-h-screen flex flex-col pb-16">
      <Header 
        status={status} 
        isScanning={isScanning} 
        onStart={startScanner} 
        onStop={stopScanner} 
      />

      <div className="flex-1 max-w-7xl mx-auto w-full px-4 pt-4">
        {activeTab === 'scanner' && (
          <ScannerTab 
            timeframe={timeframe} setTimeframe={setTimeframe}
            coinCount={coinCount} setCoinCount={setCoinCount}
            filterMode={filterMode} setFilterMode={setFilterMode}
            indicators={indicators} setIndicators={setIndicators}
            advanced={advanced} setAdvanced={setAdvanced}
            isScanning={isScanning}
          />
        )}
        {activeTab === 'orders' && (
          <OrdersTab 
            orders={openOrders} 
            onCloseOrder={(id, price) => handleCloseOrder(id, 'MANUAL', price)} 
            onShowChart={(symbol) => setSelectedCoinForChart(symbol)}
          />
        )}
        {activeTab === 'history' && (
          <HistoryTab history={history} />
        )}
        {activeTab === 'settings' && (
          <SettingsTab settings={tradeSettings} setSettings={setTradeSettings} />
        )}
      </div>

      {/* Persistent Bottom Tabs */}
      <nav className="fixed bottom-0 left-0 right-0 bg-binance-gray border-t border-binance-gray flex justify-around items-center h-16 z-50">
        <button onClick={() => setActiveTab('scanner')} className={`flex flex-col items-center flex-1 py-2 ${activeTab === 'scanner' ? 'text-yellow-500' : 'text-gray-400'}`}>
          <i className="fas fa-search-dollar text-xl mb-1"></i>
          <span className="text-xs">Quét</span>
        </button>
        <button onClick={() => setActiveTab('orders')} className={`flex flex-col items-center flex-1 py-2 relative ${activeTab === 'orders' ? 'text-yellow-500' : 'text-gray-400'}`}>
          <i className="fas fa-list-ul text-xl mb-1"></i>
          <span className="text-xs">Lệnh ({openOrders.length})</span>
          {openOrders.length > 0 && (
            <span className="absolute top-1 right-1/2 translate-x-4 bg-red-500 text-white text-[10px] rounded-full px-1.5 min-w-[18px] text-center border-2 border-[#1e2329]">
              {openOrders.length}
            </span>
          )}
        </button>
        <button onClick={() => setActiveTab('history')} className={`flex flex-col items-center flex-1 py-2 ${activeTab === 'history' ? 'text-yellow-500' : 'text-gray-400'}`}>
          <i className="fas fa-history text-xl mb-1"></i>
