        </button>
        <button onClick={() => setActiveTab('settings')} className={`flex flex-col items-center flex-1 py-2 ${activeTab === 'settings' ? 'text-yellow-500' : 'text-gray-400'}`}>
          <i className="fas fa-cog text-xl mb-1"></i>
